const p = window.__rzn_params || {};
const norm = (s) => (s || '').replace(/ /g, ' ').replace(/\s+/g, ' ').trim();
const fmt = (norm(p.format) || 'epub').toLowerCase();
const lang = norm(p.language).toLowerCase();
let idx = parseInt(p.result_index, 10);
if (!Number.isFinite(idx) || idx < 0) idx = 0;
const origin = location.origin;
const abs = (h) => { if (!h) return ''; try { return new URL(h, origin).href; } catch (e) { return ''; } };
const md5re = /md5=([a-fA-F0-9]{32})/;
const t = document.querySelector('#tablelibgen');
if (!t) {
  return { found: false, status: 'no_table', error: 'No #tablelibgen results table on this page. base_url may not be a libgen.li-family mirror.', attachment_urls: [] };
}
const rows = Array.from(t.querySelectorAll('tbody tr'));
const cands = [];
const seenFormats = new Set();
for (const r of rows) {
  const c = r.children;
  if (c.length < 9) continue;
  const titleA = c[0].querySelector('a[href*="edition.php"]') || c[0].querySelector('a[href*="file.php"]') || c[0].querySelector('a');
  const title = norm(titleA ? titleA.textContent : c[0].textContent);
  if (!title) continue;
  const ext = norm(c[7].textContent).toLowerCase();
  if (ext) seenFormats.add(ext);
  let md5 = '';
  for (const a of Array.from(c[8].querySelectorAll('a'))) {
    const m = (a.getAttribute('href') || '').match(md5re);
    if (m) { md5 = m[1].toLowerCase(); break; }
  }
  cands.push({ title: title, author: norm(c[1].textContent), publisher: norm(c[2].textContent), year: norm(c[3].textContent), language: norm(c[4].textContent), size: norm(c[6].textContent), ext: ext, md5: md5 });
}
let pool = cands.filter((x) => x.ext === fmt && x.md5);
if (!pool.length) {
  return { found: false, status: 'no_format_match', error: 'No "' + fmt + '" result with a libgen.li mirror for this query.', available_formats: Array.from(seenFormats).sort(), result_count: cands.length, attachment_urls: [] };
}
if (lang) {
  const byLang = pool.filter((x) => x.language.toLowerCase() === lang);
  if (byLang.length) pool = byLang;
}
if (idx >= pool.length) idx = 0;
const chosen = pool[idx];
let getUrl = '';
let mirrorErr = '';
try {
  const html = await fetch(origin + '/ads.php?md5=' + chosen.md5, { credentials: 'include' }).then((r) => r.text());
  const doc = new DOMParser().parseFromString(html, 'text/html');
  const links = Array.from(doc.querySelectorAll('a'));
  let getA = links.find((a) => norm(a.textContent).toUpperCase() === 'GET');
  if (!getA) getA = links.find((a) => /get\.php\?/i.test(a.getAttribute('href') || ''));
  if (getA) getUrl = abs(getA.getAttribute('href'));
} catch (e) { mirrorErr = String(e); }
if (!getUrl) {
  return { found: false, status: 'no_download_link', error: 'Found the book but could not resolve a download link on the mirror page.' + (mirrorErr ? ' (' + mirrorErr + ')' : ''), chosen: chosen, attachment_urls: [] };
}
const safe = (chosen.title || 'book').replace(/[\\/:*?"<>|]+/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 120);
const filename = safe + '.' + fmt;
return { found: true, status: 'ok', chosen: { title: chosen.title, author: chosen.author, publisher: chosen.publisher, year: chosen.year, language: chosen.language, size: chosen.size, ext: chosen.ext, md5: chosen.md5 }, download_url: getUrl, attachment_urls: [{ url: getUrl, filename: filename }] };
